export declare class TraceId {
    /**
     * traceid 高位，10 进制形式
     */
    high: string;
    /**
     * traceid 低位，10 进制形式
     */
    low: string;
    /**
     * tracerId 由高位和低位两部分组成，分别为 16 位十六进制数字组成，这里使用字符串形式的十进制数字保存。
     * @param high 数字或者字符串形式的十进制数字
     * @param low 数字或者字符串形式的十进制数字
     */
    constructor(high: string | number, low: string | number);
    /**
     * 如果 tracerId 的高位和低位都等于 0 则为无效 tracerId，调用 isValid() 返回 false。
     * @returns
     */
    isValid(): boolean;
}
